import{_ as a,c as i,o as s,aA as t}from"./chunks/framework.DPonWJ6h.js";const o="/previews/PR5389/assets/b2f4d60.C5DvdN6C.png",g=JSON.parse('{"title":"ablines","description":"","frontmatter":{},"headers":[],"relativePath":"reference/plots/ablines.md","filePath":"reference/plots/ablines.md","lastUpdated":null}'),l={name:"reference/plots/ablines.md"};function n(r,e,c,d,h,p){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="ablines" tabindex="-1">ablines <a class="header-anchor" href="#ablines" aria-label="Permalink to &quot;ablines {#ablines}&quot;">​</a></h1><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># return a new figure, axis, and plot</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">f, ax, pl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ablines</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(args</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; kw</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># creates an axis in a subfigure grid position</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ax, pl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ablines</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(f[row, col], args</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; kw</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Creates a plot in the given axis or scene.</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        pl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ablines!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ax</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Union{Scene, AbstractAxis}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, args</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; kw</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Creates a SpecApi plot, which can be used in `S.Axis(plots=[plot])`.</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SpecApi</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Ablines</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(args</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; kw</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Creates a line defined by <code>f(x) = slope * x + intercept</code> crossing a whole <code>Axis</code> at its current limits.</p><h2 id="Arguments" tabindex="-1">Arguments <a class="header-anchor" href="#Arguments" aria-label="Permalink to &quot;Arguments {#Arguments}&quot;">​</a></h2><ul><li><p><code>intercepts</code>: A <code>Real</code> or <code>AbstractVector{&lt;:Real}</code> containing y intercepts.</p></li><li><p><code>slopes</code>: A <code>Real</code> or <code>AbstractVector{&lt;:Real}</code> containing slops.</p></li></ul><h2 id="Attributes" tabindex="-1">Attributes <a class="header-anchor" href="#Attributes" aria-label="Permalink to &quot;Attributes {#Attributes}&quot;">​</a></h2><h3 id="transparency" tabindex="-1"><code>transparency</code> <a class="header-anchor" href="#transparency" aria-label="Permalink to &quot;`transparency` {#transparency}&quot;">​</a></h3><p><strong>Default:</strong> <code>false</code></p><p>Adjusts how the plot deals with transparency. In GLMakie <code>transparency = true</code> results in using Order Independent Transparency.</p><h3 id="alpha" tabindex="-1"><code>alpha</code> <a class="header-anchor" href="#alpha" aria-label="Permalink to &quot;`alpha` {#alpha}&quot;">​</a></h3><p><strong>Default:</strong> <code>1.0</code></p><p>The alpha value of the colormap or color attribute. Multiple alphas like in <code>plot(alpha=0.2, color=(:red, 0.5)</code>, will get multiplied.</p><h3 id="colormap" tabindex="-1"><code>colormap</code> <a class="header-anchor" href="#colormap" aria-label="Permalink to &quot;`colormap` {#colormap}&quot;">​</a></h3><p><strong>Default:</strong> <code>@inherit colormap :viridis</code></p><p>Sets the colormap that is sampled for numeric <code>color</code>s. <code>PlotUtils.cgrad(...)</code>, <code>Makie.Reverse(any_colormap)</code> can be used as well, or any symbol from ColorBrewer or PlotUtils. To see all available color gradients, you can call <code>Makie.available_gradients()</code>.</p><h3 id="visible" tabindex="-1"><code>visible</code> <a class="header-anchor" href="#visible" aria-label="Permalink to &quot;`visible` {#visible}&quot;">​</a></h3><p><strong>Default:</strong> <code>true</code></p><p>Controls whether the plot gets rendered or not.</p><h3 id="space" tabindex="-1"><code>space</code> <a class="header-anchor" href="#space" aria-label="Permalink to &quot;`space` {#space}&quot;">​</a></h3><p><strong>Default:</strong> <code>:data</code></p><p>Sets the transformation space for box encompassing the plot. See <code>Makie.spaces()</code> for possible inputs.</p><h3 id="colorscale" tabindex="-1"><code>colorscale</code> <a class="header-anchor" href="#colorscale" aria-label="Permalink to &quot;`colorscale` {#colorscale}&quot;">​</a></h3><p><strong>Default:</strong> <code>identity</code></p><p>The color transform function. Can be any function, but only works well together with <code>Colorbar</code> for <code>identity</code>, <code>log</code>, <code>log2</code>, <code>log10</code>, <code>sqrt</code>, <code>logit</code>, <code>Makie.pseudolog10</code>, <code>Makie.Symlog10</code>, <code>Makie.AsinhScale</code>, <code>Makie.SinhScale</code>, <code>Makie.LogScale</code>, <code>Makie.LuptonAsinhScale</code>, and <code>Makie.PowerScale</code>.</p><h3 id="inspector_hover" tabindex="-1"><code>inspector_hover</code> <a class="header-anchor" href="#inspector_hover" aria-label="Permalink to &quot;`inspector_hover` {#inspector_hover}&quot;">​</a></h3><p><strong>Default:</strong> <code>automatic</code></p><p>Sets a callback function <code>(inspector, plot, index) -&gt; ...</code> which replaces the default <code>show_data</code> methods.</p><h3 id="clip_planes" tabindex="-1"><code>clip_planes</code> <a class="header-anchor" href="#clip_planes" aria-label="Permalink to &quot;`clip_planes` {#clip_planes}&quot;">​</a></h3><p><strong>Default:</strong> <code>@inherit clip_planes automatic</code></p><p>Clip planes offer a way to do clipping in 3D space. You can set a Vector of up to 8 <code>Plane3f</code> planes here, behind which plots will be clipped (i.e. become invisible). By default clip planes are inherited from the parent plot or scene. You can remove parent <code>clip_planes</code> by passing <code>Plane3f[]</code>.</p><h3 id="highclip" tabindex="-1"><code>highclip</code> <a class="header-anchor" href="#highclip" aria-label="Permalink to &quot;`highclip` {#highclip}&quot;">​</a></h3><p><strong>Default:</strong> <code>automatic</code></p><p>The color for any value above the colorrange.</p><h3 id="ssao" tabindex="-1"><code>ssao</code> <a class="header-anchor" href="#ssao" aria-label="Permalink to &quot;`ssao` {#ssao}&quot;">​</a></h3><p><strong>Default:</strong> <code>false</code></p><p>Adjusts whether the plot is rendered with ssao (screen space ambient occlusion). Note that this only makes sense in 3D plots and is only applicable with <code>fxaa = true</code>.</p><h3 id="linestyle" tabindex="-1"><code>linestyle</code> <a class="header-anchor" href="#linestyle" aria-label="Permalink to &quot;`linestyle` {#linestyle}&quot;">​</a></h3><p><strong>Default:</strong> <code>nothing</code></p><p>Sets the dash pattern of the line. Options are <code>:solid</code> (equivalent to <code>nothing</code>), <code>:dot</code>, <code>:dash</code>, <code>:dashdot</code> and <code>:dashdotdot</code>. These can also be given in a tuple with a gap style modifier, either <code>:normal</code>, <code>:dense</code> or <code>:loose</code>. For example, <code>(:dot, :loose)</code> or <code>(:dashdot, :dense)</code>.</p><p>For custom patterns have a look at <a href="/previews/PR5389/api#Makie.Linestyle"><code>Makie.Linestyle</code></a>.</p><h3 id="inspector_label" tabindex="-1"><code>inspector_label</code> <a class="header-anchor" href="#inspector_label" aria-label="Permalink to &quot;`inspector_label` {#inspector_label}&quot;">​</a></h3><p><strong>Default:</strong> <code>automatic</code></p><p>Sets a callback function <code>(plot, index, position) -&gt; string</code> which replaces the default label generated by DataInspector.</p><h3 id="nan_color" tabindex="-1"><code>nan_color</code> <a class="header-anchor" href="#nan_color" aria-label="Permalink to &quot;`nan_color` {#nan_color}&quot;">​</a></h3><p><strong>Default:</strong> <code>:transparent</code></p><p>The color for NaN values.</p><h3 id="linecap" tabindex="-1"><code>linecap</code> <a class="header-anchor" href="#linecap" aria-label="Permalink to &quot;`linecap` {#linecap}&quot;">​</a></h3><p><strong>Default:</strong> <code>@inherit linecap</code></p><p>Sets the type of linecap used, i.e. :butt (flat with no extrusion), :square (flat with 1 linewidth extrusion) or :round.</p><h3 id="overdraw" tabindex="-1"><code>overdraw</code> <a class="header-anchor" href="#overdraw" aria-label="Permalink to &quot;`overdraw` {#overdraw}&quot;">​</a></h3><p><strong>Default:</strong> <code>false</code></p><p>Controls if the plot will draw over other plots. This specifically means ignoring depth checks in GL backends</p><h3 id="cycle" tabindex="-1"><code>cycle</code> <a class="header-anchor" href="#cycle" aria-label="Permalink to &quot;`cycle` {#cycle}&quot;">​</a></h3><p><strong>Default:</strong> <code>[:color]</code></p><p>Sets which attributes to cycle when creating multiple plots. The values to cycle through are defined by the parent Theme. Multiple cycled attributes can be set by passing a vector. Elements can</p><ul><li><p>directly refer to a cycled attribute, e.g. <code>:color</code></p></li><li><p>map a cycled attribute to a palette attribute, e.g. <code>:linecolor =&gt; :color</code></p></li><li><p>map multiple cycled attributes to a palette attribute, e.g. <code>[:linecolor, :markercolor] =&gt; :color</code></p></li></ul><h3 id="transformation" tabindex="-1"><code>transformation</code> <a class="header-anchor" href="#transformation" aria-label="Permalink to &quot;`transformation` {#transformation}&quot;">​</a></h3><p><strong>Default:</strong> <code>:automatic</code></p><p>Controls the inheritance or directly sets the transformations of a plot. Transformations include the transform function and model matrix as generated by <code>translate!(...)</code>, <code>scale!(...)</code> and <code>rotate!(...)</code>. They can be set directly by passing a <code>Transformation()</code> object or inherited from the parent plot or scene. Inheritance options include:</p><ul><li><p><code>:automatic</code>: Inherit transformations if the parent and child <code>space</code> is compatible</p></li><li><p><code>:inherit</code>: Inherit transformations</p></li><li><p><code>:inherit_model</code>: Inherit only model transformations</p></li><li><p><code>:inherit_transform_func</code>: Inherit only the transform function</p></li><li><p><code>:nothing</code>: Inherit neither, fully disconnecting the child&#39;s transformations from the parent</p></li></ul><p>Another option is to pass arguments to the <code>transform!()</code> function which then get applied to the plot. For example <code>transformation = (:xz, 1.0)</code> which rotates the <code>xy</code> plane to the <code>xz</code> plane and translates by <code>1.0</code>. For this inheritance defaults to <code>:automatic</code> but can also be set through e.g. <code>(:nothing, (:xz, 1.0))</code>.</p><h3 id="model" tabindex="-1"><code>model</code> <a class="header-anchor" href="#model" aria-label="Permalink to &quot;`model` {#model}&quot;">​</a></h3><p><strong>Default:</strong> <code>automatic</code></p><p>Sets a model matrix for the plot. This overrides adjustments made with <code>translate!</code>, <code>rotate!</code> and <code>scale!</code>.</p><h3 id="depth_shift" tabindex="-1"><code>depth_shift</code> <a class="header-anchor" href="#depth_shift" aria-label="Permalink to &quot;`depth_shift` {#depth_shift}&quot;">​</a></h3><p><strong>Default:</strong> <code>0.0</code></p><p>Adjusts the depth value of a plot after all other transformations, i.e. in clip space, where <code>-1 &lt;= depth &lt;= 1</code>. This only applies to GLMakie and WGLMakie and can be used to adjust render order (like a tunable overdraw).</p><h3 id="colorrange" tabindex="-1"><code>colorrange</code> <a class="header-anchor" href="#colorrange" aria-label="Permalink to &quot;`colorrange` {#colorrange}&quot;">​</a></h3><p><strong>Default:</strong> <code>automatic</code></p><p>The values representing the start and end points of <code>colormap</code>.</p><h3 id="color" tabindex="-1"><code>color</code> <a class="header-anchor" href="#color" aria-label="Permalink to &quot;`color` {#color}&quot;">​</a></h3><p><strong>Default:</strong> <code>@inherit linecolor</code></p><p>The color of the line.</p><h3 id="linewidth" tabindex="-1"><code>linewidth</code> <a class="header-anchor" href="#linewidth" aria-label="Permalink to &quot;`linewidth` {#linewidth}&quot;">​</a></h3><p><strong>Default:</strong> <code>@inherit linewidth</code></p><p>Sets the width of the line in pixel units</p><h3 id="inspectable" tabindex="-1"><code>inspectable</code> <a class="header-anchor" href="#inspectable" aria-label="Permalink to &quot;`inspectable` {#inspectable}&quot;">​</a></h3><p><strong>Default:</strong> <code>@inherit inspectable</code></p><p>Sets whether this plot should be seen by <code>DataInspector</code>. The default depends on the theme of the parent scene.</p><h3 id="fxaa" tabindex="-1"><code>fxaa</code> <a class="header-anchor" href="#fxaa" aria-label="Permalink to &quot;`fxaa` {#fxaa}&quot;">​</a></h3><p><strong>Default:</strong> <code>false</code></p><p>Adjusts whether the plot is rendered with fxaa (fast approximate anti-aliasing, GLMakie only). Note that some plots implement a better native anti-aliasing solution (scatter, text, lines). For them <code>fxaa = true</code> generally lowers quality. Plots that show smoothly interpolated data (e.g. image, surface) may also degrade in quality as <code>fxaa = true</code> can cause blurring.</p><h3 id="inspector_clear" tabindex="-1"><code>inspector_clear</code> <a class="header-anchor" href="#inspector_clear" aria-label="Permalink to &quot;`inspector_clear` {#inspector_clear}&quot;">​</a></h3><p><strong>Default:</strong> <code>automatic</code></p><p>Sets a callback function <code>(inspector, plot) -&gt; ...</code> for cleaning up custom indicators in DataInspector.</p><h3 id="lowclip" tabindex="-1"><code>lowclip</code> <a class="header-anchor" href="#lowclip" aria-label="Permalink to &quot;`lowclip` {#lowclip}&quot;">​</a></h3><p><strong>Default:</strong> <code>automatic</code></p><p>The color for any value below the colorrange.</p><h3 id="Basic-example" tabindex="-1">Basic example <a class="header-anchor" href="#Basic-example" aria-label="Permalink to &quot;Basic example {#Basic-example}&quot;">​</a></h3><a id="example-b2f4d60"></a><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CairoMakie</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ablines</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ablines!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], color </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:red</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:orange</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:pink</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], linestyle</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:dash</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, linewidth</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">current_figure</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><img src="'+o+'" width="600px" height="450px">',92)])])}const u=a(l,[["render",n]]);export{g as __pageData,u as default};
